/**
 * GRD-VSC-003: Requirement editor preview — dedicated webview, shared HTML base with full report,
 * editor title Preview button, side-by-side view; switching editor or opening a requirement file
 * (e.g. via satisfies link) shows that requirement’s preview.
 *
 * GRD-VSC-006: Editable description and rationale use Toast UI (WYSIWYG) in the webview; raw Markdown
 * is edited in the YAML editor. Updates apply back to the file; structure-only changes re-render HTML,
 * text-only edits sync field state without replacing the webview document.
 *
 * Preview HTML is generated by the active profile's generateSingleRequirementHtml, which uses the same
 * requirementDetailHtml as the full report — so description and rationale are rendered as
 * Markdown (GRD-HTML-004) and styling matches the exported HTML report.
 */
import * as path from "path";
import * as vscode from "vscode";
import {
  discoverProjectRoot,
  getRequirementProfile,
  loadActiveProfile,
  loadRequirements,
  STANDARD_PROFILE_ID,
} from "@gitreqd/core";
import type { RequirementProfile } from "@gitreqd/core";
import type { ParameterValue, RequirementWithSource } from "@gitreqd/core";
import { parse as parseYaml } from "yaml";
import { isRequirementDocument } from "./requirement-document.js";
import {
  applyYamlMarkdownFieldUpdate,
  type EditableMarkdownField,
} from "./yaml-field-patch.js";

function previewTitle(uri: vscode.Uri): string {
  return `Requirement Preview: ${path.basename(uri.fsPath)}`;
}

const PREVIEW_VIEW_TYPE = "gitreqd.requirementPreview";

/** GRD-VSC-003: Delegated click handler so links work after WYSIWYG updates (GRD-VSC-006). */
const PREVIEW_LINK_SCRIPT =
  `
<script>
(function() {
  const vscode = acquireVsCodeApi();
  document.body.addEventListener('click', function(e) {
    var t = e.target;
    if (!t || !t.closest) return;
    var a = t.closest('a[href^="#"]');
    if (!a) return;
    var href = a.getAttribute('href');
    if (href && href.length > 1) {
      e.preventDefault();
      e.stopPropagation();
      vscode.postMessage({ type: 'openPreview', requirementId: href.slice(1) });
    }
  });
})();
</scr` +
  `ipt>
`;

